Javascript.logic:
var issueDate = Services.getValue(IssueDate.dataBinding);
if(IssueDate.validate() == null)
{
	Services.setValue("/ds/var/app/OracleReportForm/CM_WAREX/ReportRun", "false");	
	if (!CaseManUtils.isBlank(issueDate)) {
		checkExecutedWarrantsExist(issueDate);
	}
	else {
		Services.setValue(_executedWarrantsExistXPath, "true");
	}
}

Javascript.validate:
var issueDate = Services.getValue(IssueDate.dataBinding);
var issueDateObj = CaseManUtils.isBlank(issueDate) ? null : CaseManUtils.createDate(issueDate);
var ec = null;
if(issueDateObj != null)
{
  ec = validatePastDate(issueDateObj);     
}
return ec;

Javascript.miscCode:
			var _executedWarrantsExistXPath = "/ds/var/page/OracleReportForm/ExecutedWarrantsExist";

			Status_RunReportButton.validationList = ["IssueDate"];	
			
			function checkExecutedWarrantsExist(issueDate)
			{
				var params = new ServiceParams();
				params.addSimpleParameter("issueDate", CaseManUtils.convertDateToDisplay(issueDate));
				// var owningCourtCode = Services.getValue("/ds/var/page/tmp/OwningCourtCode");  // returns null
				var owningCourtCode = CaseManUtils.getUserParameter(CaseManFormParameters.COURTNUMBER_XPATH);
				params.addSimpleParameter("owningCourtCode", owningCourtCode);

				Services.callService("checkExecutedWarrantsExist", params, checkExecutedWarrantsExist, true);
			}
			checkExecutedWarrantsExist.onSuccess = function(dom)
			{
				if (dom != null) {
					var results = dom.selectSingleNode("/ExecutedWarrantsFound");
					if (results != null) {
						if (XML.getNodeTextContent(results) == 0) {
							Services.setValue(_executedWarrantsExistXPath, "false");
							alert("There are no Warrants to be printed.");
						}
						else {
							Services.setValue(_executedWarrantsExistXPath, "true");
						}
					}
					else {
						this.onError();
					}
				}
				else {
					this.onError();
				}
			}
			checkExecutedWarrantsExist.onError = function()
			{
				alert("Error querying database to check count of executed Warrants");
			}

			function validatePastDate(dateObj)
			{    
			  var todayDateObj = CaseManUtils.createDate(getTodaysDate());
			  // changed code to be efficient and correct.  date cannot be in the future
			  // but can be 'today'
			  // removed if(CaseManUtils.compareDates(todayDateObj, dateObj) == 0 || CaseManUtils.compareDates(todayDateObj, dateObj) == 1)
			  if(CaseManUtils.compareDates(todayDateObj, dateObj) == 1)
			  {
			    ec = ErrorCode.getErrorCode("CaseMan_dateCannotBeInTheFuture_Msg");
			    return faildedValidation (ec);
			  }
			  else
			  {
				return null;
			  }      
			  return null;   
			}			
			
			Status_RunReportButton.enableOn = [_executedWarrantsExistXPath,
											    "/ds/var/app/OracleReportForm/CM_WAREX/ReportRun"];
			Status_RunReportButton.isEnabled = function()
			{
				
			var returnValue = false;
			if (Services.getValue(_executedWarrantsExistXPath) == "true") {
				returnValue = true;
			}
			
			// defect 5305. Don't allow the report to run twice as prints empty report 2nd time.
			var reportRun = Services.getValue("/ds/var/app/OracleReportForm/CM_WAREX/ReportRun");
			if(reportRun != null){
				if(reportRun == "true"){
					returnValue = false;
				}
			}		
			
						
			return returnValue;
			}
